render.css:
.heatmap-wrapper { display: flex; flex-direction: column; gap: 8px; }
.matrix-container { display: grid; grid-template-columns: repeat(20, 1fr); gap: 2px; aspect-ratio: 1; position: relative; overflow: hidden; }
.matrix-cell { background: var(--ct-text-strong); border-radius: 1px; }
.matrix-scanner { position: absolute; left: 0; right: 0; height: 2px; background: var(--ct-text-strong); box-shadow: 0 0 8px var(--ct-text-strong); animation: scan 3s ease-in-out infinite; }
.ruler { display: flex; justify-content: space-between; font-size: 10px; color: var(--ct-text-muted); font-variant-numeric: tabular-nums; }
@keyframes scan { 0%, 100% { top: 0%; opacity: 1; } 50% { top: 98%; opacity: 0.5; } }

canvas.init:
function init(container, params) {
  var cells = params.cells || 200;
  var sparsity = params.sparsity != null ? params.sparsity : 0.7;
  var frag = document.createDocumentFragment();
  for (var i = 0; i < cells; i++) {
    var cell = document.createElement('div');
    cell.className = 'matrix-cell';
    var opacity = Math.random() > sparsity ? (Math.random() * 0.8 + 0.2) : (Math.random() * 0.15);
    cell.style.opacity = opacity.toFixed(2);
    frag.appendChild(cell);
  }
  container.appendChild(frag);
}
